# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

namespace EventBookingSystem
{
    public class TicketPurchaseService
    {
        private readonly TicketInventoryContext _context;

        public TicketPurchaseService(TicketInventoryContext context)
        {
            _context = context;
        }

        public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
        {
            // Check available seats for the event
            var availableSeats = await _context.Events
                .Where(e => e.EventId == eventId)
                .Select(e => e.AvailableSeats)
                .SingleAsync();

            if (availableSeats < quantity)
            {
                return false; // Not enough seats available
            }

            // Update inventory with the purchase quantity
            var updatedInventory = await _context.Tickets
                .Where(t => t.EventId == eventId)
                .Select(t => t.AvailableSeats)
                .SingleAsync();

            updatedInventory -= quantity;

            _context.Events.Update(e => e.EventId == eventId, e => new Event { AvailableSeats = updatedInventory });

            await _context.SaveChangesAsync();

            return true; // Purchase successful
        }
    }
}